System.register([],function(t,e){"use strict";return{execute:function(){document.querySelectorAll("[data-toggle-modal]").forEach(t=>{t.addEventListener("click",t=>{t.stopPropagation();const e=t.target.getAttribute("data-toggle-modal"),o=document.getElementById(e);if(o){const t=o.getAttribute("active")===String(!0);o.setAttribute("active",!t)}})}),document.querySelectorAll("[data-modal-move]").forEach(t=>{const e=document.getElementById("modal-holder");e&&e.appendChild(t)})}}});
